PRAGMA defer_foreign_keys=TRUE;
CREATE TABLE users (
  id TEXT PRIMARY KEY,
  email TEXT UNIQUE NOT NULL,
  name TEXT NOT NULL,
  password_hash TEXT NOT NULL,
  role TEXT DEFAULT 'instructor',
  academy_id TEXT NOT NULL,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP, status TEXT DEFAULT 'active', subjects TEXT, last_login_at DATETIME,
  FOREIGN KEY (academy_id) REFERENCES academies(id)
);
CREATE TABLE sessions (
  id TEXT PRIMARY KEY,
  user_id TEXT NOT NULL,
  refresh_token TEXT NOT NULL UNIQUE,
  expires_at DATETIME NOT NULL,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE
);
CREATE TABLE academies (
  id TEXT PRIMARY KEY,
  name TEXT NOT NULL,
  phone TEXT,
  address TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
, default_class_id TEXT, slug TEXT, owner_id TEXT, plan TEXT DEFAULT 'free', max_students INTEGER DEFAULT 30, max_teachers INTEGER DEFAULT 3, is_active INTEGER DEFAULT 1, logo_url TEXT, expires_at DATETIME);
CREATE TABLE classes (
  id TEXT PRIMARY KEY,
  academy_id TEXT NOT NULL,
  name TEXT NOT NULL,
  grade TEXT,
  day_of_week INTEGER,
  start_time TEXT,
  end_time TEXT,
  instructor_id TEXT,
  capacity INTEGER,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (academy_id) REFERENCES academies(id),
  FOREIGN KEY (instructor_id) REFERENCES users(id)
);
CREATE TABLE students (
  id TEXT PRIMARY KEY,
  academy_id TEXT NOT NULL,
  name TEXT NOT NULL,
  class_id TEXT,
  contact TEXT,
  guardian_contact TEXT,
  enrollment_date DATE,
  status TEXT DEFAULT 'active',
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP, grade TEXT, subjects TEXT DEFAULT '[]', school TEXT,
  FOREIGN KEY (academy_id) REFERENCES academies(id),
  FOREIGN KEY (class_id) REFERENCES classes(id)
);
CREATE TABLE attendance (
  id TEXT PRIMARY KEY,
  student_id TEXT NOT NULL,
  class_id TEXT NOT NULL,
  date DATE NOT NULL,
  status TEXT DEFAULT 'present',
  notes TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (student_id) REFERENCES students(id),
  FOREIGN KEY (class_id) REFERENCES classes(id),
  UNIQUE(student_id, class_id, date)
);
CREATE TABLE reports (
  id TEXT PRIMARY KEY,
  student_id TEXT NOT NULL,
  month TEXT NOT NULL,
  content TEXT,
  pdf_url TEXT,
  generated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  sent_at DATETIME,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (student_id) REFERENCES students(id)
);
CREATE TABLE messages (
  id TEXT PRIMARY KEY,
  sender_id TEXT NOT NULL,
  recipient_id TEXT NOT NULL,
  content TEXT NOT NULL,
  is_read BOOLEAN DEFAULT FALSE,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (sender_id) REFERENCES users(id),
  FOREIGN KEY (recipient_id) REFERENCES users(id)
);
CREATE TABLE audit_logs (
  id TEXT PRIMARY KEY,
  user_id TEXT NOT NULL,
  action TEXT NOT NULL,
  resource_type TEXT,
  resource_id TEXT,
  changes TEXT,
  ip_address TEXT,
  user_agent TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (user_id) REFERENCES users(id)
);
CREATE TABLE report_send_configs (
  id TEXT PRIMARY KEY,
  academy_id TEXT NOT NULL,
  start_date DATE NOT NULL,
  end_date DATE NOT NULL,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (academy_id) REFERENCES academies(id),
  UNIQUE(academy_id)
);
CREATE TABLE IF NOT EXISTS "exams" (
  id TEXT PRIMARY KEY,
  academy_id TEXT NOT NULL,
  class_id TEXT,
  name TEXT NOT NULL,
  exam_month TEXT,
  date DATE NOT NULL,
  total_score REAL,
  is_active BOOLEAN DEFAULT 0,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME, exam_type TEXT NOT NULL DEFAULT 'monthly', term TEXT,
  FOREIGN KEY (academy_id) REFERENCES academies(id),
  FOREIGN KEY (class_id) REFERENCES classes(id)
);
CREATE TABLE exam_settings (
  id TEXT PRIMARY KEY,
  academy_id TEXT NOT NULL,
  active_exam_month TEXT NOT NULL,
  updated_by TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (academy_id) REFERENCES academies(id),
  UNIQUE(academy_id)
);
CREATE TABLE student_teachers (student_id TEXT NOT NULL, teacher_id TEXT NOT NULL, created_at TEXT DEFAULT (datetime('now')), is_homeroom INTEGER NOT NULL DEFAULT 0, PRIMARY KEY (student_id, teacher_id), FOREIGN KEY (student_id) REFERENCES students(id) ON DELETE CASCADE, FOREIGN KEY (teacher_id) REFERENCES users(id) ON DELETE CASCADE);
CREATE TABLE report_sends (id TEXT PRIMARY KEY, academy_id TEXT NOT NULL, student_id TEXT NOT NULL, year_month TEXT NOT NULL, share_url TEXT NOT NULL, image_path TEXT NOT NULL, sent_by TEXT NOT NULL, sent_at TEXT NOT NULL, UNIQUE(academy_id, student_id, year_month));
CREATE TABLE class_students (id TEXT PRIMARY KEY, class_id TEXT NOT NULL, student_id TEXT NOT NULL, created_at TEXT DEFAULT (datetime('now')), FOREIGN KEY (class_id) REFERENCES classes(id) ON DELETE CASCADE, FOREIGN KEY (student_id) REFERENCES students(id) ON DELETE CASCADE, UNIQUE(class_id, student_id));
CREATE TABLE absences (id TEXT PRIMARY KEY, student_id TEXT NOT NULL, class_id TEXT NOT NULL, absence_date DATE NOT NULL, reason TEXT DEFAULT '', notified_by TEXT DEFAULT '', notified_at TEXT, status TEXT DEFAULT 'absent', recorded_by TEXT, created_at TEXT DEFAULT (datetime('now')), FOREIGN KEY (student_id) REFERENCES students(id), FOREIGN KEY (class_id) REFERENCES classes(id), UNIQUE(student_id, class_id, absence_date));
CREATE TABLE makeups (id TEXT PRIMARY KEY, absence_id TEXT NOT NULL, scheduled_date DATE, completed_date DATE, status TEXT DEFAULT 'pending', notes TEXT DEFAULT '', created_at TEXT DEFAULT (datetime('now')), updated_at TEXT DEFAULT (datetime('now')), scheduled_start_time TEXT, scheduled_end_time TEXT, FOREIGN KEY (absence_id) REFERENCES absences(id) ON DELETE CASCADE, UNIQUE(absence_id));
CREATE TABLE notices (id TEXT PRIMARY KEY, academy_id TEXT NOT NULL, author_id TEXT NOT NULL, title TEXT NOT NULL, content TEXT DEFAULT '', category TEXT DEFAULT 'general', is_pinned INTEGER DEFAULT 0, due_date DATE, created_at TEXT DEFAULT (datetime('now')), updated_at TEXT DEFAULT (datetime('now')), FOREIGN KEY (academy_id) REFERENCES academies(id), FOREIGN KEY (author_id) REFERENCES users(id));
CREATE TABLE notice_reads (id TEXT PRIMARY KEY, notice_id TEXT NOT NULL, user_id TEXT NOT NULL, read_at TEXT DEFAULT (datetime('now')), FOREIGN KEY (notice_id) REFERENCES notices(id) ON DELETE CASCADE, FOREIGN KEY (user_id) REFERENCES users(id), UNIQUE(notice_id, user_id));
CREATE TABLE action_items (id TEXT PRIMARY KEY, academy_id TEXT NOT NULL, notice_id TEXT, title TEXT NOT NULL, description TEXT DEFAULT '', assigned_to TEXT NOT NULL, assigned_by TEXT NOT NULL, due_date DATE, status TEXT DEFAULT 'pending', completed_at TEXT, created_at TEXT DEFAULT (datetime('now')), updated_at TEXT DEFAULT (datetime('now')), FOREIGN KEY (academy_id) REFERENCES academies(id), FOREIGN KEY (notice_id) REFERENCES notices(id) ON DELETE SET NULL, FOREIGN KEY (assigned_to) REFERENCES users(id), FOREIGN KEY (assigned_by) REFERENCES users(id));
CREATE TABLE exam_review_settings (
  id TEXT PRIMARY KEY,
  academy_id TEXT NOT NULL,
  active_term TEXT NOT NULL,          -- '2026-1'
  active_exam_type TEXT NOT NULL,     -- 'midterm' | 'final'
  updated_by TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (academy_id) REFERENCES academies(id),
  UNIQUE(academy_id)
);
CREATE TABLE exam_review_sends (
  id TEXT PRIMARY KEY,
  academy_id TEXT NOT NULL,
  student_id TEXT NOT NULL,
  term TEXT NOT NULL,
  exam_type TEXT NOT NULL,
  share_url TEXT NOT NULL,
  image_path TEXT NOT NULL,
  sent_by TEXT NOT NULL,
  sent_at TEXT NOT NULL,
  UNIQUE(academy_id, student_id, term, exam_type)
);
CREATE TABLE d1_migrations(
		id         INTEGER PRIMARY KEY AUTOINCREMENT,
		name       TEXT UNIQUE,
		applied_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP NOT NULL
);
CREATE TABLE enrollments (
  id TEXT PRIMARY KEY,
  student_id TEXT NOT NULL,
  day TEXT NOT NULL,            -- '월'|'화'|'수'|'목'|'금'|'토'|'일'
  start_time TEXT NOT NULL,     -- 'HH:mm'
  end_time TEXT NOT NULL,       -- 'HH:mm'
  subject TEXT,                 -- '수학' 등, NULL 허용
  created_at TEXT DEFAULT (datetime('now')),
  updated_at TEXT DEFAULT (datetime('now')),
  FOREIGN KEY (student_id) REFERENCES students(id) ON DELETE CASCADE
);
CREATE TABLE realtime_sessions (
  id TEXT PRIMARY KEY,
  student_id TEXT NOT NULL,
  teacher_id TEXT NOT NULL,         -- 체크인한 선생님 (본인 담당)
  academy_id TEXT NOT NULL,
  date TEXT NOT NULL,                -- 'YYYY-MM-DD' (검색 인덱스용)
  check_in_time TEXT NOT NULL,       -- ISO datetime
  check_out_time TEXT,               -- ISO datetime (체크아웃 전 NULL)
  status TEXT NOT NULL,              -- 'active'|'paused'|'completed'|'overtime'
  scheduled_minutes INTEGER NOT NULL DEFAULT 0,
  added_minutes INTEGER NOT NULL DEFAULT 0,
  scheduled_start_time TEXT,         -- 'HH:mm' (enrollment 에서 복사)
  scheduled_end_time TEXT,           -- 'HH:mm'
  pause_history TEXT NOT NULL DEFAULT '[]',  -- JSON
  subject TEXT,
  created_at TEXT DEFAULT (datetime('now')),
  updated_at TEXT DEFAULT (datetime('now')), makeup_id TEXT,
  FOREIGN KEY (student_id) REFERENCES students(id) ON DELETE CASCADE,
  FOREIGN KEY (teacher_id) REFERENCES users(id),
  FOREIGN KEY (academy_id) REFERENCES academies(id)
);
CREATE TABLE attendance_records (
  id TEXT PRIMARY KEY,
  session_id TEXT,                    -- 원본 realtime_session 참조 (감사용)
  student_id TEXT NOT NULL,
  teacher_id TEXT NOT NULL,
  academy_id TEXT NOT NULL,
  date TEXT NOT NULL,                  -- 'YYYY-MM-DD'
  check_in_time TEXT NOT NULL,
  check_out_time TEXT NOT NULL,
  scheduled_start_time TEXT,
  scheduled_end_time TEXT,
  scheduled_minutes INTEGER NOT NULL,
  net_minutes INTEGER NOT NULL,        -- 순수 수업시간 (총 - 정지)
  total_paused_minutes INTEGER NOT NULL DEFAULT 0,
  pause_count INTEGER NOT NULL DEFAULT 0,
  pause_history TEXT NOT NULL DEFAULT '[]',
  subject TEXT,
  was_late INTEGER NOT NULL DEFAULT 0,
  was_overtime INTEGER NOT NULL DEFAULT 0,
  note TEXT,
  created_at TEXT DEFAULT (datetime('now')),
  FOREIGN KEY (student_id) REFERENCES students(id),
  FOREIGN KEY (teacher_id) REFERENCES users(id),
  FOREIGN KEY (academy_id) REFERENCES academies(id)
);
CREATE TABLE print_materials (
  id TEXT PRIMARY KEY,
  student_id TEXT NOT NULL,
  title TEXT NOT NULL,
  memo TEXT DEFAULT '',
  status TEXT NOT NULL DEFAULT 'todo',  -- 'todo' | 'done'
  file_url TEXT DEFAULT '',
  created_by TEXT NOT NULL,
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  completed_at TEXT,
  FOREIGN KEY (student_id) REFERENCES students(id)
);
CREATE TABLE invitations (
  id TEXT PRIMARY KEY,
  academy_id TEXT NOT NULL,
  code TEXT UNIQUE NOT NULL,
  role TEXT DEFAULT 'instructor',
  created_by TEXT NOT NULL,
  used_by TEXT,
  expires_at DATETIME NOT NULL,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (academy_id) REFERENCES academies(id),
  FOREIGN KEY (created_by) REFERENCES users(id)
);
CREATE TABLE meetings (
  id TEXT PRIMARY KEY,
  academy_id TEXT NOT NULL,
  title TEXT NOT NULL DEFAULT '회의',
  audio_url TEXT,
  transcript TEXT,
  summary TEXT,
  key_decisions TEXT,        -- JSON array
  status TEXT NOT NULL DEFAULT 'recording',  -- recording | transcribing | summarizing | done | error
  error_message TEXT,
  duration_seconds INTEGER,
  participants TEXT,          -- JSON array of names
  created_by TEXT NOT NULL,
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at TEXT NOT NULL DEFAULT (datetime('now')),
  FOREIGN KEY (academy_id) REFERENCES academies(id),
  FOREIGN KEY (created_by) REFERENCES users(id)
);
CREATE TABLE meeting_actions (
  id TEXT PRIMARY KEY,
  meeting_id TEXT NOT NULL,
  title TEXT NOT NULL,
  assignee_name TEXT,
  due_date TEXT,
  status TEXT NOT NULL DEFAULT 'pending',  -- pending | done
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  FOREIGN KEY (meeting_id) REFERENCES meetings(id) ON DELETE CASCADE
);
CREATE TABLE gacha_students (
  id TEXT PRIMARY KEY,
  academy_id TEXT NOT NULL,
  teacher_id TEXT NOT NULL,
  name TEXT NOT NULL,
  pin_hash TEXT NOT NULL,
  pin_salt TEXT NOT NULL,
  grade TEXT,
  status TEXT DEFAULT 'active',
  created_at DATETIME DEFAULT (datetime('now')),
  updated_at DATETIME, school TEXT,
  UNIQUE(academy_id, teacher_id, name)
);
CREATE TABLE gacha_cards (
  id TEXT PRIMARY KEY,
  academy_id TEXT NOT NULL,
  teacher_id TEXT NOT NULL,
  student_id TEXT,
  type TEXT NOT NULL DEFAULT 'text',
  question TEXT,
  question_image TEXT,
  answer TEXT NOT NULL,
  topic TEXT,
  chapter TEXT,
  grade TEXT,
  box INTEGER DEFAULT 1,
  success_count INTEGER DEFAULT 0,
  fail_count INTEGER DEFAULT 0,
  last_review DATETIME,
  created_at DATETIME DEFAULT (datetime('now')), updated_at DATETIME,
  FOREIGN KEY (student_id) REFERENCES gacha_students(id) ON DELETE SET NULL
);
CREATE TABLE proofs (
  id TEXT PRIMARY KEY,
  academy_id TEXT NOT NULL,
  created_by TEXT NOT NULL,
  title TEXT NOT NULL,
  grade TEXT NOT NULL,
  chapter TEXT,
  difficulty INTEGER DEFAULT 1,
  description TEXT,
  description_image TEXT,
  is_shared INTEGER DEFAULT 0,
  share_count INTEGER DEFAULT 0,
  created_at DATETIME DEFAULT (datetime('now')),
  updated_at DATETIME
, theorem_statement TEXT, subject TEXT, source_path TEXT);
CREATE TABLE proof_steps (
  id TEXT PRIMARY KEY,
  proof_id TEXT NOT NULL,
  step_order INTEGER NOT NULL,
  content TEXT NOT NULL,
  content_image TEXT,
  blanks_json TEXT,
  hint TEXT,
  FOREIGN KEY (proof_id) REFERENCES proofs(id) ON DELETE CASCADE
);
CREATE TABLE proof_shares (
  id TEXT PRIMARY KEY,
  original_proof_id TEXT NOT NULL,
  shared_by TEXT NOT NULL,
  copied_by TEXT,
  copied_academy_id TEXT,
  copied_proof_id TEXT,
  copied_at DATETIME,
  FOREIGN KEY (original_proof_id) REFERENCES proofs(id)
);
CREATE TABLE gacha_sessions (
  id TEXT PRIMARY KEY,
  student_id TEXT NOT NULL,
  session_date TEXT NOT NULL,
  cards_drawn INTEGER DEFAULT 0,
  cards_target INTEGER DEFAULT 10,
  proofs_done INTEGER DEFAULT 0,
  proofs_target INTEGER DEFAULT 5,
  started_at DATETIME DEFAULT (datetime('now')),
  completed_at DATETIME,
  UNIQUE(student_id, session_date),
  FOREIGN KEY (student_id) REFERENCES gacha_students(id) ON DELETE CASCADE
);
CREATE TABLE gacha_card_results (
  id TEXT PRIMARY KEY,
  student_id TEXT NOT NULL,
  card_id TEXT NOT NULL,
  session_id TEXT,
  result TEXT NOT NULL,
  box_before INTEGER,
  box_after INTEGER,
  reviewed_at DATETIME DEFAULT (datetime('now')),
  FOREIGN KEY (student_id) REFERENCES gacha_students(id) ON DELETE CASCADE,
  FOREIGN KEY (card_id) REFERENCES gacha_cards(id) ON DELETE CASCADE,
  FOREIGN KEY (session_id) REFERENCES gacha_sessions(id) ON DELETE SET NULL
);
CREATE TABLE proof_results (
  id TEXT PRIMARY KEY,
  student_id TEXT NOT NULL,
  proof_id TEXT NOT NULL,
  session_id TEXT,
  mode TEXT NOT NULL,
  score INTEGER,
  time_spent INTEGER,
  detail_json TEXT,
  box INTEGER DEFAULT 1,
  attempted_at DATETIME DEFAULT (datetime('now')),
  FOREIGN KEY (student_id) REFERENCES gacha_students(id) ON DELETE CASCADE,
  FOREIGN KEY (proof_id) REFERENCES proofs(id) ON DELETE CASCADE,
  FOREIGN KEY (session_id) REFERENCES gacha_sessions(id) ON DELETE SET NULL
);
CREATE TABLE proof_assignments (
  id TEXT PRIMARY KEY,
  student_id TEXT NOT NULL,
  proof_id TEXT NOT NULL,
  assigned_by TEXT NOT NULL,
  assigned_at DATETIME DEFAULT (datetime('now')),
  UNIQUE(student_id, proof_id),
  FOREIGN KEY (student_id) REFERENCES gacha_students(id) ON DELETE CASCADE,
  FOREIGN KEY (proof_id) REFERENCES proofs(id) ON DELETE CASCADE
);
CREATE TABLE exam_periods (
  id TEXT PRIMARY KEY,
  academy_id TEXT NOT NULL,
  title TEXT NOT NULL,
  period_month TEXT NOT NULL,
  status TEXT DEFAULT 'preparing',
  created_by TEXT NOT NULL,
  created_at DATETIME DEFAULT (datetime('now')),
  updated_at DATETIME DEFAULT (datetime('now')),
  UNIQUE(academy_id, period_month)
);
CREATE TABLE exam_papers (
  id TEXT PRIMARY KEY,
  exam_period_id TEXT NOT NULL,
  academy_id TEXT NOT NULL,
  title TEXT NOT NULL,
  grade_filter TEXT,
  is_custom INTEGER DEFAULT 0,
  created_at DATETIME DEFAULT (datetime('now')),
  FOREIGN KEY (exam_period_id) REFERENCES exam_periods(id) ON DELETE CASCADE
);
CREATE TABLE proof_givens (
  id TEXT PRIMARY KEY,
  proof_id TEXT NOT NULL,
  kind TEXT NOT NULL DEFAULT 'definition',
  label TEXT,
  content TEXT NOT NULL,
  order_idx INTEGER DEFAULT 0,
  FOREIGN KEY (proof_id) REFERENCES proofs(id) ON DELETE CASCADE
);
CREATE TABLE proof_phases (
  id TEXT PRIMARY KEY,
  proof_id TEXT NOT NULL,
  phase_no INTEGER NOT NULL,
  phase_type TEXT NOT NULL,
  prompt TEXT NOT NULL,
  model_answer TEXT,
  UNIQUE(proof_id, phase_no),
  FOREIGN KEY (proof_id) REFERENCES proofs(id) ON DELETE CASCADE
);
CREATE TABLE proof_phase_items (
  id TEXT PRIMARY KEY,
  phase_id TEXT NOT NULL,
  item_key TEXT NOT NULL,
  content TEXT NOT NULL,
  correct_answer TEXT,
  meta_json TEXT,
  order_idx INTEGER DEFAULT 0,
  FOREIGN KEY (phase_id) REFERENCES proof_phases(id) ON DELETE CASCADE
);
CREATE TABLE proof_phase_results (
  id TEXT PRIMARY KEY,
  student_id TEXT NOT NULL,
  proof_id TEXT NOT NULL,
  phase_no INTEGER NOT NULL,
  session_id TEXT,
  submitted_json TEXT NOT NULL,
  verify_status TEXT,
  score INTEGER,
  issues_json TEXT,
  time_spent INTEGER,
  attempted_at DATETIME DEFAULT (datetime('now')),
  FOREIGN KEY (student_id) REFERENCES gacha_students(id) ON DELETE CASCADE,
  FOREIGN KEY (proof_id) REFERENCES proofs(id) ON DELETE CASCADE,
  FOREIGN KEY (session_id) REFERENCES gacha_sessions(id) ON DELETE SET NULL
);
CREATE TABLE proof_figures (
  id TEXT PRIMARY KEY,
  proof_id TEXT NOT NULL,
  phase_id TEXT,
  svg_content TEXT NOT NULL,
  coords_json TEXT NOT NULL,
  verify_meta_json TEXT,
  verify_result_json TEXT,
  highlight_keys TEXT,
  alt_text TEXT NOT NULL,
  review_status TEXT DEFAULT 'pending',
  created_at DATETIME DEFAULT (datetime('now')),
  FOREIGN KEY (proof_id) REFERENCES proofs(id) ON DELETE CASCADE,
  FOREIGN KEY (phase_id) REFERENCES proof_phases(id) ON DELETE SET NULL
);
CREATE TABLE paper_handouts (
  id TEXT PRIMARY KEY,
  academy_id TEXT NOT NULL,
  title TEXT NOT NULL,
  exam_type TEXT NOT NULL,         -- 'midterm' | 'final' | 'performance'
  subject TEXT,
  school TEXT,
  grade TEXT,
  exam_year INTEGER,
  semester INTEGER,                -- 1 | 2
  file_key TEXT,
  file_name TEXT,
  file_size INTEGER,
  content_type TEXT,
  memo TEXT DEFAULT '',
  created_by TEXT NOT NULL,
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at TEXT NOT NULL DEFAULT (datetime('now'))
);
CREATE TABLE paper_handout_distributions (
  id TEXT PRIMARY KEY,
  paper_id TEXT NOT NULL,
  student_id TEXT NOT NULL,
  academy_id TEXT NOT NULL,
  source TEXT NOT NULL DEFAULT 'auto',
  distributed_at TEXT NOT NULL DEFAULT (datetime('now')),
  viewed_at TEXT,
  UNIQUE(paper_id, student_id),
  FOREIGN KEY (paper_id) REFERENCES paper_handouts(id) ON DELETE CASCADE,
  FOREIGN KEY (student_id) REFERENCES students(id) ON DELETE CASCADE
);
CREATE TABLE IF NOT EXISTS "exam_assignments" (
  id TEXT PRIMARY KEY,
  exam_period_id TEXT NOT NULL,
  exam_paper_id TEXT NOT NULL,
  student_id TEXT NOT NULL,
  academy_id TEXT NOT NULL,
  created_check INTEGER DEFAULT 0,
  printed INTEGER DEFAULT 0,
  reviewed INTEGER DEFAULT 0,
  drive_link TEXT,
  score REAL,
  memo TEXT,
  created_at DATETIME DEFAULT (datetime('now')), exam_date TEXT, exam_status TEXT DEFAULT 'scheduled', absence_reason TEXT, rescheduled_date TEXT, rescheduled_memo TEXT, adhoc_session_id TEXT,
  UNIQUE(exam_period_id, student_id),
  FOREIGN KEY (exam_period_id) REFERENCES exam_periods(id) ON DELETE CASCADE,
  FOREIGN KEY (exam_paper_id) REFERENCES exam_papers(id),
  FOREIGN KEY (student_id) REFERENCES students(id)
);
CREATE TABLE adhoc_sessions (
  id TEXT PRIMARY KEY,
  student_id TEXT NOT NULL,
  teacher_id TEXT NOT NULL,
  academy_id TEXT NOT NULL,
  date TEXT NOT NULL,              -- 'YYYY-MM-DD'
  start_time TEXT NOT NULL,        -- 'HH:mm'
  end_time TEXT NOT NULL,          -- 'HH:mm'
  subject TEXT,
  reason TEXT,                     -- '시간표변경','보충수업','시험대비','대타','기타'
  status TEXT DEFAULT 'scheduled', -- 'scheduled'|'completed'|'cancelled'
  created_at TEXT DEFAULT (datetime('now')),
  FOREIGN KEY (student_id) REFERENCES students(id) ON DELETE CASCADE,
  FOREIGN KEY (teacher_id) REFERENCES users(id),
  FOREIGN KEY (academy_id) REFERENCES academies(id)
);
CREATE TABLE IF NOT EXISTS "grades" (
  id TEXT PRIMARY KEY,
  student_id TEXT NOT NULL,
  exam_id TEXT NOT NULL,
  score REAL,
  comments TEXT,
  graded_at DATETIME,
  graded_by TEXT,
  created_at DATETIME DEFAULT (datetime('now')),
  year_month TEXT,
  FOREIGN KEY (student_id) REFERENCES students(id) ON DELETE CASCADE,
  FOREIGN KEY (exam_id) REFERENCES exams(id) ON DELETE CASCADE
);
CREATE TABLE study_units (
  id TEXT PRIMARY KEY,
  academy_id TEXT NOT NULL,
  textbook TEXT NOT NULL,
  name TEXT NOT NULL,
  kind TEXT NOT NULL DEFAULT 'unit',
  order_idx INTEGER NOT NULL DEFAULT 0,
  created_by TEXT,
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);
CREATE TABLE student_study_progress (
  id TEXT PRIMARY KEY,
  academy_id TEXT NOT NULL,
  student_id TEXT NOT NULL,
  unit_id TEXT NOT NULL,
  understanding INTEGER,
  status TEXT NOT NULL DEFAULT 'not_started',
  note TEXT,
  updated_by TEXT,
  updated_at TEXT NOT NULL DEFAULT (datetime('now')),
  UNIQUE(student_id, unit_id),
  FOREIGN KEY (student_id) REFERENCES students(id) ON DELETE CASCADE,
  FOREIGN KEY (unit_id) REFERENCES study_units(id) ON DELETE CASCADE
);
CREATE TABLE vocab_words (
  id TEXT PRIMARY KEY,
  academy_id TEXT NOT NULL,
  student_id TEXT NOT NULL,
  english TEXT NOT NULL,
  korean TEXT NOT NULL,
  box INTEGER NOT NULL DEFAULT 1,          -- 1..5
  blank_type TEXT NOT NULL DEFAULT 'korean', -- korean|english|both
  status TEXT NOT NULL DEFAULT 'approved', -- pending|approved
  added_by TEXT NOT NULL DEFAULT 'teacher',-- teacher|student
  review_count INTEGER NOT NULL DEFAULT 0,
  wrong_count INTEGER NOT NULL DEFAULT 0,
  created_at DATETIME DEFAULT (datetime('now')),
  updated_at DATETIME,
  FOREIGN KEY (student_id) REFERENCES gacha_students(id) ON DELETE CASCADE
);
CREATE TABLE vocab_grammar_qa (
  id TEXT PRIMARY KEY,
  academy_id TEXT NOT NULL,
  student_id TEXT,                          -- NULL = 교사가 직접 작성
  question TEXT NOT NULL,
  answer TEXT,
  status TEXT NOT NULL DEFAULT 'pending',   -- pending|answered
  answered_by TEXT,                         -- teacher|ai
  include_in_print INTEGER NOT NULL DEFAULT 0,
  created_at DATETIME DEFAULT (datetime('now')),
  answered_at DATETIME,
  FOREIGN KEY (student_id) REFERENCES gacha_students(id) ON DELETE SET NULL
);
CREATE TABLE vocab_textbooks (
  id TEXT PRIMARY KEY,
  academy_id TEXT NOT NULL,
  school TEXT,
  grade TEXT,
  semester TEXT,
  title TEXT NOT NULL,
  created_by TEXT,
  created_at DATETIME DEFAULT (datetime('now'))
);
CREATE TABLE vocab_textbook_words (
  id TEXT PRIMARY KEY,
  textbook_id TEXT NOT NULL,
  unit TEXT,
  english TEXT NOT NULL,
  korean TEXT NOT NULL,
  sentence TEXT,
  FOREIGN KEY (textbook_id) REFERENCES vocab_textbooks(id) ON DELETE CASCADE
);
CREATE TABLE vocab_print_jobs (
  id TEXT PRIMARY KEY,
  academy_id TEXT NOT NULL,
  student_id TEXT NOT NULL,
  word_ids_json TEXT NOT NULL,              -- 출제된 vocab_words.id 배열
  grammar_ids_json TEXT,                    -- 포함된 문법 Q&A id 배열
  pdf_r2_key TEXT,                          -- (선택) 캐시된 PDF
  created_by TEXT,
  created_at DATETIME DEFAULT (datetime('now')),
  FOREIGN KEY (student_id) REFERENCES gacha_students(id) ON DELETE CASCADE
);
CREATE TABLE vocab_grade_results (
  id TEXT PRIMARY KEY,
  print_job_id TEXT NOT NULL,
  word_id TEXT NOT NULL,
  correct INTEGER NOT NULL,                 -- 0|1
  box_before INTEGER,
  box_after INTEGER,
  graded_at DATETIME DEFAULT (datetime('now')),
  FOREIGN KEY (print_job_id) REFERENCES vocab_print_jobs(id) ON DELETE CASCADE,
  FOREIGN KEY (word_id) REFERENCES vocab_words(id) ON DELETE CASCADE
);
CREATE TABLE exam_attempts (
  id TEXT PRIMARY KEY,
  exam_assignment_id TEXT NOT NULL,
  student_id TEXT NOT NULL,
  academy_id TEXT NOT NULL,
  realtime_session_id TEXT,                    -- 어떤 수업 입실 중에 친 시험인지 (회고 분석용)

  duration_minutes INTEGER NOT NULL,           -- 이 시험의 총 제한시간 (분)

  status TEXT NOT NULL DEFAULT 'ready',
    -- ready    : 배정만 됨, 미시작
    -- running  : 진행 중
    -- paused   : 일시정지
    -- submitted: 학생 제출
    -- expired  : 시간 종료 (자동)
    -- voided   : 무효 처리

  started_at TEXT,                             -- ISO8601 (running/이후)
  ended_at TEXT,                               -- 종료 시각 (submitted/expired/voided)

  pause_history TEXT DEFAULT '[]',             -- JSON: [{pausedAt, resumedAt, reason, byUserId}]
  total_paused_seconds INTEGER DEFAULT 0,     -- 누적 정지 시간

  proctor_user_id TEXT,                        -- 시작 처리한 감독 교사 (audit)
  submit_note TEXT,                            -- 제출 시 비고 (옵션)

  created_at DATETIME DEFAULT (datetime('now')),
  updated_at DATETIME DEFAULT (datetime('now')),

  FOREIGN KEY (exam_assignment_id) REFERENCES exam_assignments(id) ON DELETE CASCADE,
  FOREIGN KEY (student_id) REFERENCES students(id),
  FOREIGN KEY (academy_id) REFERENCES academies(id)
);
CREATE TABLE assignments (
  id TEXT PRIMARY KEY,
  academy_id TEXT NOT NULL,
  created_by TEXT NOT NULL,                    -- users.id (teacher/admin)
  title TEXT NOT NULL,
  instructions TEXT,
  kind TEXT NOT NULL DEFAULT 'general',        -- 'perf_eval' | 'exam_paper' | 'general'
  due_at DATETIME,
  attached_file_key TEXT,                      -- R2 key (선생님 첨부; 양식·시험지 등)
  attached_file_name TEXT,
  status TEXT NOT NULL DEFAULT 'published',    -- 'published' | 'closed'
  created_at DATETIME DEFAULT (datetime('now')),
  updated_at DATETIME DEFAULT (datetime('now'))
);
CREATE TABLE assignment_targets (
  id TEXT PRIMARY KEY,
  assignment_id TEXT NOT NULL,
  student_id TEXT NOT NULL,                    -- gacha_students.id
  academy_id TEXT NOT NULL,
  status TEXT NOT NULL DEFAULT 'assigned',     -- 'assigned'|'submitted'|'reviewed'|'needs_resubmit'|'completed'
  assigned_at DATETIME DEFAULT (datetime('now')),
  last_submitted_at DATETIME,
  last_reviewed_at DATETIME,
  UNIQUE(assignment_id, student_id)
);
CREATE TABLE assignment_submissions (
  id TEXT PRIMARY KEY,
  target_id TEXT NOT NULL,
  student_id TEXT NOT NULL,
  academy_id TEXT NOT NULL,
  note TEXT,
  files TEXT NOT NULL DEFAULT '[]',            -- JSON: [{key, name, size, mime}]
  submitted_at DATETIME DEFAULT (datetime('now'))
);
CREATE TABLE assignment_responses (
  id TEXT PRIMARY KEY,
  target_id TEXT NOT NULL,
  submission_id TEXT,                          -- nullable: 특정 제출 미연결도 가능
  teacher_id TEXT NOT NULL,                    -- users.id
  academy_id TEXT NOT NULL,
  comment TEXT,
  file_key TEXT,                               -- R2 key (첨삭본 PDF 등; nullable)
  file_name TEXT,
  action TEXT NOT NULL DEFAULT 'accept',       -- 'accept'|'needs_resubmit'
  created_at DATETIME DEFAULT (datetime('now'))
);
CREATE TABLE student_play_state (
  student_id TEXT NOT NULL,
  academy_id TEXT NOT NULL,
  state_json TEXT NOT NULL DEFAULT '{}',
  updated_at TEXT NOT NULL DEFAULT (datetime('now')),
  PRIMARY KEY (student_id, academy_id)
);
CREATE TABLE consultations (
  id TEXT PRIMARY KEY,
  academy_id TEXT NOT NULL,
  student_id TEXT NOT NULL,
  author_id TEXT NOT NULL,          -- 작성 선생님
  channel TEXT NOT NULL,            -- phone | sms | kakao | in_person | other
  category TEXT NOT NULL DEFAULT 'monthly', -- monthly | pre_exam | post_exam | ad_hoc
  consulted_at TEXT NOT NULL,       -- 실제 상담 일시 (ISO)
  subjects TEXT,                    -- JSON array, 다과목 상담 시 과목 태그
  summary TEXT NOT NULL,            -- 상담 요약 (공유 대상 본문)
  parent_sentiment TEXT,            -- positive | neutral | concerned | null
  follow_up TEXT,                   -- 다음 액션/후속 상담 메모
  follow_up_due TEXT,               -- YYYY-MM-DD, 후속 일정
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at TEXT NOT NULL DEFAULT (datetime('now')),
  FOREIGN KEY (student_id) REFERENCES students(id) ON DELETE CASCADE,
  FOREIGN KEY (author_id) REFERENCES users(id) ON DELETE RESTRICT,
  FOREIGN KEY (academy_id) REFERENCES academies(id) ON DELETE CASCADE
);
CREATE TABLE student_external_schedules (
  id TEXT PRIMARY KEY,
  academy_id TEXT NOT NULL,
  student_id TEXT NOT NULL,
  author_id TEXT NOT NULL,
  kind TEXT NOT NULL,               -- other_subject | other_academy | exam | event
  title TEXT NOT NULL,              -- 예: "수학 1:1 (화목 7시)", "중간고사 수학"
  starts_at TEXT,                   -- ISO 또는 YYYY-MM-DD (시험/이벤트용)
  ends_at TEXT,
  recurrence TEXT,                  -- weekly | once | null (자유 표기)
  location TEXT,                    -- 타학원명 등
  note TEXT,
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at TEXT NOT NULL DEFAULT (datetime('now')),
  FOREIGN KEY (student_id) REFERENCES students(id) ON DELETE CASCADE,
  FOREIGN KEY (author_id) REFERENCES users(id) ON DELETE RESTRICT,
  FOREIGN KEY (academy_id) REFERENCES academies(id) ON DELETE CASCADE
);
CREATE TABLE student_teacher_notes (
  id              TEXT PRIMARY KEY,
  academy_id      TEXT NOT NULL,
  student_id      TEXT NOT NULL,
  author_id       TEXT NOT NULL,        -- 작성한 교과 선생님 (users.id)
  subject         TEXT NOT NULL,        -- '수학' | '영어' | ... (학원 subjects 어휘)
  category        TEXT NOT NULL,        -- attitude | understanding | homework | exam | etc
  sentiment       TEXT NOT NULL,        -- positive | neutral | concern
  tags            TEXT,                 -- JSON array (예: ["보강필요","집중부족"])
  content         TEXT NOT NULL,        -- 본문 (1~3줄 권장, 최대 1000자)
  source          TEXT NOT NULL DEFAULT 'manual', -- manual | post_class | post_exam | post_assignment
  source_ref_id   TEXT,                 -- exam_id / assignment_id 등 (선택)
  visibility      TEXT NOT NULL DEFAULT 'staff',  -- staff | homeroom_only | parent_share
  period_tag      TEXT NOT NULL,        -- 'YYYY-WW' 또는 'YYYY-MM' (요약 단위 인덱스)
  created_at      TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at      TEXT NOT NULL DEFAULT (datetime('now')),
  FOREIGN KEY (academy_id) REFERENCES academies(id) ON DELETE CASCADE,
  FOREIGN KEY (student_id) REFERENCES students(id) ON DELETE CASCADE,
  FOREIGN KEY (author_id)  REFERENCES users(id)    ON DELETE RESTRICT
);
CREATE TABLE live_sessions (
  id              TEXT PRIMARY KEY,
  academy_id      TEXT NOT NULL,
  teacher_id      TEXT NOT NULL,
  student_id      TEXT NOT NULL,
  subject         TEXT NOT NULL,
  status          TEXT NOT NULL DEFAULT 'active', -- active | ended | abandoned
  started_at      TEXT NOT NULL DEFAULT (datetime('now')),
  ended_at        TEXT,
  duration_sec    INTEGER,
  problem_text    TEXT,
  problem_r2_key  TEXT,
  teacher_solution_text   TEXT,
  teacher_solution_r2_key TEXT,
  student_answer_text     TEXT,
  student_answer_r2_key   TEXT,
  note_id         TEXT,
  FOREIGN KEY (academy_id) REFERENCES academies(id) ON DELETE CASCADE,
  FOREIGN KEY (teacher_id) REFERENCES users(id) ON DELETE RESTRICT,
  FOREIGN KEY (student_id) REFERENCES students(id) ON DELETE CASCADE
);
