INSERT INTO "notices" ("id","academy_id","author_id","title","content","category","is_pinned","due_date","created_at","updated_at") VALUES('ntc-cy-01','acad-5386360c','user-aa73897d','4월 월말평가 안내','4월 25일(금) 수학/영어 월말평가\n\n시험 범위:\n- 수학: 4월 전범위 (하이머딩거 선생님)\n- 영어: Unit 3~4 (소라카 선생님)\n\n학생들에게 미리 안내 부탁드립니다.\n특히 야스오는 시험 당일 반드시 출석하도록 요네 형에게도 연락 부탁.','exam',1,'2026-04-25','2026-04-07','2026-04-07');
INSERT INTO "notices" ("id","academy_id","author_id","title","content","category","is_pinned","due_date","created_at","updated_at") VALUES('ntc-cy-02','acad-5386360c','user-aa73897d','학부모 상담 주간 (4/21~25)','이번 주 학부모 상담입니다.\n\n특별 유의 학생:\n- 야스오: 출결 문제 → 요네 형과 상담 필수\n- 징크스: 수업 태도 → 바이 언니와 상담\n- 이즈리얼: 집중력 → 아버지와 상담\n\n각 선생님께서 담당 보호자와 시간 조율 부탁드립니다.','general',0,'2026-04-21','2026-04-10','2026-04-10');
INSERT INTO "notices" ("id","academy_id","author_id","title","content","category","is_pinned","due_date","created_at","updated_at") VALUES('ntc-cy-03','acad-5386360c','user-canyon-t1','중2 수학 교재 변경','야스오, 아리 학생 수학 교재를\n"개념원리 RPM" → "쎈 수학"으로 변경합니다.\n\n사유: 야스오 학생에게 더 많은 연습 문제가 필요.\n4월 셋째 주부터 적용.','general',0,NULL,'2026-04-08','2026-04-08');
INSERT INTO "notices" ("id","academy_id","author_id","title","content","category","is_pinned","due_date","created_at","updated_at") VALUES('206a4b43-ea10-47b5-845d-62d24b920a67','acad-1','user-57ppx9v61','[회의록] 4월 학습 방향 논의',replace('4월 학습 방향 논의 회의에서는 중간고사 준비에 대한 전략을 세웠습니다. 수학 기본 개념 복습의 필요성이 제기되었으며, 특히 중2 학생들의 함수 파트 보강을 위해 다음 주부터 보충 수업을 진행하기로 결정했습니다. 또한, 고1 학생들의 내신 대비를 위해 주 1회 모의고사를 실시하여 5월 중간고사 전까지 총 4회 진행할 계획입니다.\n\n주요 결정사항:\n1. 중2 학생 함수 파트 보충 수업 진행\n2. 고1 학생 내신 대비 모의고사 주 1회 실시','\n',char(10)),'meeting',0,NULL,'2026-04-13 15:08:44','2026-04-13 15:08:44');
INSERT INTO "notices" ("id","academy_id","author_id","title","content","category","is_pinned","due_date","created_at","updated_at") VALUES('3592371a-9e21-42f5-9a5c-a0dbf527d59c','acad-1','user-57ppx9v61','아동학대 신고자 의무 교육 (사이버교육 이수 후 이수증 제출)',replace('- 경기도 평생학습포털: (https://www.gseek.kr)\n- 서울시 평생학습포털: (http://sll.seoul.go.kr)','\n',char(10)),'education',1,'2026-05-31','2026-04-16 14:49:13','2026-04-16 14:49:13');
