INSERT INTO "meetings" ("id","academy_id","title","audio_url","transcript","summary","key_decisions","status","error_message","duration_seconds","participants","created_by","created_at","updated_at") VALUES('d19ac53e-b02b-4fd3-8135-85ab1b6985f9','acad-1','4월 학습 방향 논의',NULL,replace('서재용: 이번 달 중간고사 준비 어떻게 할까요? 수학 기본 개념 복습이 필요한 학생이 많아요.\n김선생: 맞아요. 특히 중2 학생들 함수 파트가 약해요. 다음 주부터 보충 수업을 넣으면 좋겠어요.\n서재용: 그러면 화요일 6시에 보충반 열죠. 김선생님이 담당해주세요. 기한은 이번 달 말까지.\n김선생: 네, 그리고 고1 학생들은 내신 대비 모의고사를 주 1회 실시하는 건 어떨까요?\n서재용: 좋습니다. 금요일 7시에 모의고사 시간 잡아요. 제가 담당할게요. 5월 중간고사 전까지 4회 진행합시다.','\n',char(10)),'4월 학습 방향 논의 회의에서는 중간고사 준비에 대한 전략을 세웠습니다. 수학 기본 개념 복습의 필요성이 제기되었으며, 특히 중2 학생들의 함수 파트 보강을 위해 다음 주부터 보충 수업을 진행하기로 결정했습니다. 또한, 고1 학생들의 내신 대비를 위해 주 1회 모의고사를 실시하여 5월 중간고사 전까지 총 4회 진행할 계획입니다.','["중2 학생 함수 파트 보충 수업 진행","고1 학생 내신 대비 모의고사 주 1회 실시"]','done',NULL,NULL,'["서재용","김선생"]','user-57ppx9v61','2026-04-13 15:07:38','2026-04-13 15:07:46');
INSERT INTO "meeting_actions" ("id","meeting_id","title","assignee_name","due_date","status","created_at") VALUES('2d46b9c4-7804-41f3-a1e2-badbb62e7895','d19ac53e-b02b-4fd3-8135-85ab1b6985f9','중2 학생 함수 파트 보충 수업 개설 및 진행','김선생','2024-04-30','pending','2026-04-13 15:07:46');
