INSERT INTO "proofs" ("id","academy_id","created_by","title","grade","chapter","difficulty","description","description_image","is_shared","share_count","created_at","updated_at","theorem_statement","subject","source_path") VALUES('prf_m1_vertical','acad-1','system','맞꼭지각의 크기는 같다','중1','평면도형',1,'두 직선이 한 점에서 만날 때 마주보는 두 각의 크기는 같음을 평각의 성질로 증명',NULL,1,0,'2026-04-15 02:52:59',NULL,'두 직선이 교차할 때 ∠1 = ∠3 (맞꼭지각)','geometry','middle/05_중1_기하/vertical_angles.typ');
