INSERT INTO "proof_phases" ("id","proof_id","phase_no","phase_type","prompt","model_answer") VALUES('ph_tas_3','prf_m1_tri_angle_sum',3,'blank_paper','꼭짓점 A를 지나고 BC에 평행한 직선을 이용하여 ∠A+∠B+∠C=180°임을 증명하시오.','보조선 ℓ∥BC를 A에 긋고, 엇각으로 ∠B=∠DAB, ∠C=∠EAC, 평각으로 ∠DAB+∠BAC+∠CAE=180°, 대입하면 ∠A+∠B+∠C=180°.');
