INSERT INTO "proof_phases" ("id","proof_id","phase_no","phase_type","prompt","model_answer") VALUES('ph_va_3','prf_m1_vertical',3,'blank_paper','두 직선의 교점에서 생기는 맞꼭지각 ∠1=∠3을 증명하시오.','∠1+∠2=180°(평각), ∠2+∠3=180°(평각). 두 식에서 ∠1=180°−∠2=∠3.');
