INSERT INTO "paper_handouts" ("id","academy_id","title","exam_type","subject","school","grade","exam_year","semester","file_key","file_name","file_size","content_type","memo","created_by","created_at","updated_at") VALUES('7264cdc4-6bc3-411f-9bc6-9816448ca912','acad-1','2026년도 시지고 중간고사 범위','midterm','수학','시지고','고2',2026,1,'exam-papers/acad-1/1776350524559-1aacd2c8-0c92-4c42-b21d-0fc19ed783b6.jpg','KakaoTalk_20260416_233519127.jpg',388455,'image/jpeg',replace('1. 확률과 통계\n시험 범위:\n\nI. 경우의 수\n\nII. 확률: 01. 조건부확률까지\n\n교과서: p.10 ~ p.62, p.67 ~ p.73 중 시험 범위에 해당되는 모든 문제\n\n기타: 수업 시간에 나눠준 학습지 전부\n\n문항 수: 객관식 15문항 내외, 서술형 6문항 내외\n\n2. 대수 (Algebra)\n시험 범위:\n\nI. 지수와 로그\n\nII. 지수함수와 로그함수\n\nIII. 삼각함수\n\n일반각과 호도법\n\n삼각함수의 뜻\n\n삼각함수의 그래프\n\n교과서: 처음 ~ p.89의 모든 내용, p.98 ~ p.100 중 해당 내용\n\n기타: 수업 시간에 나눠준 학습지 전부\n\n문항 수: 객관식 15문항 내외, 단답형 1문항(5점), 서술형 5문항 내외','\n',char(10)),'user-57ppx9v61','2026-04-16 14:42:05','2026-04-16 14:42:05');
INSERT INTO "paper_handouts" ("id","academy_id","title","exam_type","subject","school","grade","exam_year","semester","file_key","file_name","file_size","content_type","memo","created_by","created_at","updated_at") VALUES('477fbb18-8dab-41c6-8c4d-d7f69981d64b','acad-1','2026년도 고산중 중간고사 범위','midterm','수학','고산중','중3',2026,1,'exam-papers/acad-1/1776350796681-1848284b-21f0-4576-9f34-340a05403d6e.jpg','KakaoTalk_20260415_180029068.jpg',2366841,'image/jpeg',replace('교과서: p.11 ~ p.83 내용 및 문제\n\n교과서 추가: p.107 ~ p.109에서 내용 시험 범위 문제만 해당\n\n기타: 교과서 범위에 해당하는 학습지','\n',char(10)),'user-57ppx9v61','2026-04-16 14:46:38','2026-04-16 14:46:38');
INSERT INTO "paper_handouts" ("id","academy_id","title","exam_type","subject","school","grade","exam_year","semester","file_key","file_name","file_size","content_type","memo","created_by","created_at","updated_at") VALUES('1118a6d8-94cd-4de5-9c48-4a5630d8a855','acad-1','2026년도 노변중 중간고사','midterm','수학','노변중','중2',2026,1,'exam-papers/acad-1/1776350884649-66c96b65-52cd-49d6-9ba8-cfa1b8a44389.png','KakaoTalk_20260414_161200237.png',206351,'image/png',replace('- 교과서: 처음 ~ p.71\n\n\n- 교과서 추가: p.90 ~ p.91 (대단원 평가 중 해당 범위 문제)\n\n\n- 교과서 추가: p.262 ~ p.264\n\n\n- 기타: 해당 범위 학습지','\n',char(10)),'user-57ppx9v61','2026-04-16 14:48:06','2026-04-16 14:48:06');
INSERT INTO "paper_handouts" ("id","academy_id","title","exam_type","subject","school","grade","exam_year","semester","file_key","file_name","file_size","content_type","memo","created_by","created_at","updated_at") VALUES('47b44e45-bc70-4317-b30d-49b1650a8927','acad-1','2026년도 삼육고 중간고사','midterm','수학','삼육고','고1',2026,1,NULL,NULL,NULL,NULL,replace('범위: 처음 ~ Ⅱ. 방정식과 부등식 - 2. 복소수와 이차방정식 - 02. 이차방정식과 이차함수\n\n페이지: ~ p.75까지\n\n주요 내용: 다항식의 연산부터 복소수, 그리고 이차함수의 그래프와 그 관계까지 포함되는 범위입니다.','\n',char(10)),'user-57ppx9v61','2026-04-16 14:51:38','2026-04-16 14:51:38');
