INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-425bf24b','student-fbcy3xfzp','exam-march-25767a87',73,' 이번 정기고사에서는 73점을 받았습니다. 기본적인 문제들에 대해서 잘 풀고 있습니다. 문제를 응용하는 경우에는 조금은 어려워 하는 모습을 보이고 있습니다.특히 조건이나 상황이 복잡해는 경우에 이러한 경향이 크게 나타납니다. 기존의 메인교제와 병행으로 학생이 어려워하는 부분들에 대해서 수업중이나 따로 숙제로 혼자서 연습을 해줄 수 있게 숙제로 내고 있습니다. 평소에 수업태도도 좋은 편입니다. 수학개념 암기를 잘 할 수 있도록, 제가 만들어놓은 암기 시스템으로 이번에 틀린 곱셈공식을 외우게 할 생각입니다. ','2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-4a96e577','student-rks9au7mm','exam-march-25767a87',34,'이번 3월 정기고사에서는 34점을 받았습니다. 기존에 나간 지도가 적기도하고, 계산을 어려워해서 계산을 위주로 시험을 냈습니다. 수업을 진행했을떄 수학에 대해서 띄엄띄엄 모르고 있어서 문제를 풀기를 어려워하고 있습니다. 그럴때에는 교제보다 약간 쉬운 문제를 풀이를 하고 있습니다. 그러고 난 이후에 다시 본교제를 들어가면 어느정도 문제를 잘 풀고 있습니다. 하기싫어하는 학생이라기 보다는 할려고하는데 잘 안되는 학생에 가까운것 같습니다. 그래서 쉬운문제를 단계단계별로 할려고 생각하고 있습니다. ','2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-0db095f4','student-q5ecu8748','exam-march-25767a87',79,replace('이번 정기고사에서는 79점을 받았습니다.\n수업태도나 문제풀이, 끈기와 같은 성향들이 좋은편이다보니 수업이나 시험을 잘하고 있습니다.수업 떄 수학 문제를 모델링하는 일차방정식이나 부등식의 응용에 대해서 어려워하고 있습니다.\n이러한 문제들은 독해력이 필요한 문제다보니 수학뿐만 아니라 문장 속 조건을 수식으로 바꾸는 훈련이 필요해서, 비슷한 유형을 반복적으로 많이 풀려서 익히게 하고 있습니다. \n지금은 방정식 풀이를 많이 틀리고 계산 실수를 줄이는 단계라서 부담 없이 매일 7문제씩 꾸준히 풀게 하고 있습니다. 이 루틴이 쌓이면 응용 문제로 넘어갈 예정입니다.\n\n학생의 경우에는 수업태도도 좋고, 문제도 잘 풀고 있다보니 제가 자체 제작한 증명이나 서술형을 잘 풀 수 있는 교제도 같이 숙제로 내주고 있습니다. 학생도 잘 풀고 있고, 줘도 군말없이 잘하고 있습니다. 서술형이나 수행평가는 문제 풀이를 비롯해서 사고력을 요구를 하는 문제들이 많다보니 미리미리 준비를 하고 있습니다','\n',char(10)),'2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-74488053','student-p3kgxnsyw','exam-march-25767a87',45,replace('이번 정기고사에서는 55점을 받았습니다. 앞의 순환소수와 방정식부분에서 계산을 잘하고 있습니다. 하지만 뒤에 연립방정식에서 손도 못대고 있었습니다. 최근에 배운것에 대해서 충분한 학습이 되지 않아서 그런것도 있어보입니다. 칭잔하고 싶은점은 학교에서 모르는 유인물이나 내가 모르는것들을 선생님한테 요청을 해서 문제를 많이 풀어보려고 하고 있습니다. 평소에는 숙제를 10문제 내외로 적게 숙제를 주고 있었습니다. 슬슬 시험기간이고 학교유인물이나 학생이 어려워하는 문제들에 대해서 조금더 많이 풀리게하면서 문제에 대한 자신감을 가지고 문제를 풀 수 있도록 지도를 하겠습니다.\n\n화요일 수업의 경우에는 주도적으로 순환소수의 자릿수 계산을 어려워해서 20문제 정도 뽑아주고, 풀어보고 같이 메겨봤는데 문제를 충분히 풀고 이해가 되다 보니 학생도 잘 하고 있습니다','\n',char(10)),'2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-8158a3c2','student-r558f899h','exam-march-25767a87',60,replace('태영이는 수업 태도도 정말 좋고 숙제도 빠짐없이 잘 해오고 있습니다. \n지금 아쉬운 부분은 올림 계산을 가끔 실수하는 것과, 구구단이 아직 완전히 손에 익지 않아서 곱셈·나눗셈에서 조금 어려워하지만, 자주 반복하면서 훈련하면서 실수를 줄여갈 예정입니댜.\n또한 앞으로 매 수업마다 구구단을 짧게 반복하는 루틴을 넣어서 조금씩 손에 익혀갈 예정입니다.','\n',char(10)),'2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-1da67fb7','student-a7wi0zma6','exam-march-25767a87',44,replace('  우선 좋은 소식부터 말씀드리면, 방정식과 부등식 문제는 전부 다 맞췄습니다. 사실 지효가 처음 왔을 때 기초 계산부터 다시 잡아야 하는\n  상황이었어요. 그래서 매 수업 시작할 때 5분씩 기초 계산을 꾸준히 시켜왔는데, 그게 이번 시험에서 그대로 결과로 나온 거라 저도\n  뿌듯했습니다.\n\n  점수가 44점으로 낮아 보이실 수 있는데, 사실 이번 시험 범위 뒤쪽이 중학교 3학년 새 단원인 제곱근(루트) 파트였어요. 이제 막 배우기 시작한\n  단원이다 보니 아직 익숙하지 않아서 거기서 많이 빠졌고, 그 부분을 빼면 앞부분은 완벽하게 맞은 거예요.\n\n  앞으로는 제곱근 단원도 지금까지 해온 방식 그대로, 개념 설명보다는 문제를 많이 풀면서 자연스럽게 익숙해지게 할 생각입니다. 지효가 문제를\n  직접 풀 때 집중력이 확 올라오는 스타일이에요. 그래서 설명은 짧게 하고 바로 문제로 들어가는 방식으로 수업하고 있는데, 이번 방정식 결과를\n  보니 이 방법이 지효한테 잘 맞는 것 같습니다.\n','\n',char(10)),'2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-d9e192c2','student-nb8y8m656','exam-march-25767a87',71,replace('이번 정기고사에서는 71점이 나왔는데, 과목별로 보면 확률과 통계는 8문제 중 7개를 맞출 만큼 안정적으로 잘 하고 있습니다. 지수 쪽은 응용 문제에서 조금 더   보강이 필요한 상황이라 지금 집중적으로 다루고 있습니다.\n\n학생이 모르는 문제를 그냥 넘기지 않고 다시 돌아와서 확인하는 습관이 있습니다. 이게 생각보다 쉽지 않은 건데, 이 학생은 자연스럽게 하고 있어서 저도 보면서 좋다고 생각하고 있습니다. \n그 습관을 살려서 취약한 유형은 문제를 많이 풀면서 손에 익히게 하는 방향으로 수업하고 있습니다.\n\n한 가지 더, 요즘 실수가 간간이 나오는 편인데, 앞으로는 틀린 문제를 오답노트에 직접 정리하는 방식을 도입해서 같은 실수를 반복하지 않도록 잡아갈 예정입니다.\n','\n',char(10)),'2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-ddbc27ff','student-9bsetl4ct','exam-march-25767a87',13,NULL,'2026-04-09T16:24:38.319Z','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-c087720e','student-6cxbm886s','exam-march-25767a87',7,'이번 정기고사에서는 7점을 받았습니다. 베이직쎈을 숭버을 하고 있는데, 개념이 살짝만 바꿔도 어려워 하고 있습니다. 무리하게 진도나 어려운 문제를 나기보다는 풀었던 문제를 숫자만 바꿔서 문제를 풀게하고 있습니다.','2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-9f0b1491','student-0mc8orloi','exam-march-25767a87',27,'이번 정기고사에서는 27점을 받았습니다. 문제는 잘 풀고 있으나, 문제를 꼬운 문제들이나 사고력을 필요로 하는 문제들은 어려워합니다. 그리고 어느정도 개념을 충분히 숙지가 필요한데 그 부분도 부분부분이 안되어 있는 모습을 보입니다. 개념이 외우거나 그러한 부분들에 대해서는 제가 수업 외적으로 프로그램을 통해서 외우게하고, 수업중에는 문제에 대해서 사고를 할 수 있도록 문제를 왜 이렇게 풀었는지 물어보고 있습니다.','2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-b3034f51','student-t1xikskhy','exam-march-25767a87',20,'이번 정기고사에서는 20점을 받았습니다. 평소에도 과묵하게 주는 문제들을 잘 풀고 있습니다. 푸는 양은 많은데 실수가 자주 보입니다. 부호 실수 또는 개념 적용을 어려워하고 있습니다. 그래서 옆에서 제가 지도를 해주는 식으로 많이 하고 있습니다.','2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-d6599632','student-mtoq5wqb6','exam-march-25767a87',16,'이번 정기고사에서는 16점을 받았습니다. 어려운 문제보다는 교과서 또는 중간정도 수준의 문제를 실수를 줄이는 쪽으로 방향을 잡아서 수업을 하고 있습니다. 학생이 사용하는 학교교제를 이용한 문제 은행을 구축을 해서, 학생이 모르거나 어려워하는 문제들에 대해서 맞춤형으로 숙제 및 진도를 나가고 있습니다. 아직까지는 문제는 어려워하고, 문제 푸록 쉬고 하는게 많으나 처음 봤을 때보다는 이제는 7문제 정도는 연속적으로 풀 수 있습니다','2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-4a930eee','student-ue92sdab0','exam-march-25767a87',34,'이번 정기고사에서는 34점을 받았습니다. 난이도 있는 문제보다는 기초적인 문제에 대해서 계산실수 또는 개념을 적용을 하는 것을 어려워 합니다. 그렇다보니 실수하는 부분을 하나하나 잡아가면서 수업을 하고 있습니다. 수학적 개념을 암기를 하기를 어려워하고 있습니다. 그래서 같은 문제에 대해서 유사한 문제를 많이 풀어보면서 자신감을 가지는 방법으로 수업을 진행하고 있습니다','2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-ea4f4722','student-5645a3fs4','exam-march-25767a87',80,'이번 정기고사에서는 80점을 받았습니다. 다른 학생들에 비해서 이해력도 뛰어나고 실수도 별로 안하는 학생입니다. 하나 아쉬운점이 수업시간에 이야기를 많이 할려다보니, 집중력이 풀어질 떄가 종종 있습니다. 이럴때는 강하게 잡아서 다시 수업을 하도록 하고 있습니다. 실수가 많지 않고, 사고력이 뛰어난 학생입니다. 그래서 다른 학생들은 개념이나 실수에 대해서 제가 고치려고 하는데 학생은 이미 잘하다보니 조금더 고난이도 문제를 더 풀어보게 할 생각입니다','2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-895eadec','student-4s1rdnhpb','exam-march-25767a87',41,'시험대비 문제풀이와 오답정리에 집중하고 있습니다. 오답 정리를 통해 어떤 유형의 문제들을 집중해서 다루어 봐야 하는지 체크하면서 수업 진행할 예정입니다.','2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-1ed1ab48','student-b8tu5sggp','exam-march-25767a87',16,'이번 정기고사에서는 16점을 받았습니다. 선생님의 도움 없이 혼자서 해결을 할려고 하는 학생입니다.제가 문제풀이를 봐도 실수를 하는 경향이 있기는 하지만, 자신이 실수를 하고 있다는 점이나 자신이 어려워하는 부분을 잘 인지를 하고 있습니다. 그렇다보니, 서술형으로 문제를 더 잘 풀어 볼 수 있도록 문제를 따로 제작을 할 예정입니다','2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-99e0c5a1','student-k8kamd4y8','exam-march-25767a87',54,'시험대비 문제풀이와 오답정리에 집중하고 있습니다. 오답 정리를 통해 어떤 유형의 문제들을 집중해서 다루어 봐야 하는지 체크하면서 수업 진행할 예정입니다.','2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-a3e43f0a','student-s54ihowlx','exam-march-25767a87',47,'이번 정기고사에서는 47점을 받았습니다. 문제지보다는 학교수업을 집중으로 준비를 하고 있습니다. 학교교제를 바탕으로 문제은행을 구축을 해서 학생이 어려워하는 문제를 꾸준히 풀어보게 하고 있습니다. 개념적인 문제들을 어려워하는데 충분한 설명과 많은 문제들을 통해서 수정해나가고 있습니다','2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-ddd30562','student-vosetxjdm','exam-march-25767a87',34,'이번 정기고사에서는 34점을 받았습니다. 이번 중간고사가 없습니다. 문제를 RPM 문제지를 풀기 어려워하는 모습을 보입니다. 제가 물어봐서 문제점을 파악을 했는데, 문제풀이에 집중을 하다보니, 선행개념이나 현행 개념들이 암기가 안되어 있어서 어려워합니다. 그렇다보니 제가 만든 암기 프로그램을 통해서 이러한 부분들 학원이나 학원외에도 암기를 하기 쉽게 만들어서 하고 있습니다. 고3이고 모르는 개념을 암기를 하거나 수업을 하기보다는 그때그떄모르는 부분을 설명을해주고 암기 시스템으로 제대로 외웠는지 관리를 합니다','2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-67cb934d','student-j5ohbrke6','exam-march-25767a87',21,'이번 정고고사에서는 21점을 받았습니다. 수업태도도 좋고, 열심히 하다보니 1학년 진도를 잘나가고 있습니다. 이번 시험에는 어려운 문제와 쉬운 문제를 섞어서 출제를 했는데, 쉬운 문제는 다 맞추는 모습을 보이고 있습니다. 난이도 있는 문제를 나기기보다는, 기존의 진도는 그대로 나가면서, 문제의 중간 난이도의 문제와 검정고시 문제를 가져와서 수업시간에도 이러한 개념들이 검정고시에서 어떻게 사용되고 어떻게 풀면 되는지에 대한 수업을 진행을 할 예정입니다','2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-ed097e34','student-tme649c7a','exam-march-25767a87',73,'시험대비 문제풀이와 오답정리에 집중하고 있습니다. 오답 정리를 통해 어떤 유형의 문제들을 집중해서 다루어 봐야 하는지 체크하면서 수업 진행할 예정입니다.','2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-4f597332','student-xi4i833h1','exam-march-25767a87',33,'시험대비 문제풀이와 오답정리에 집중하고 있습니다. 오답 정리를 통해 어떤 유형의 문제들을 집중해서 다루어 봐야 하는지 체크하면서 수업 진행할 예정입니다.','2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-8d1a1dc8','student-j59157jnh','exam-march-25767a87',87,'분수의 나눗셈 단원 마무리 하고 각기둥 진도 나가고 있습니다. 도형 단원은 태현이가 어렵지 않게 받아들이고 있어서 잘 따라오고 있습니다.','2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-a425a86b','student-a7wi0zma6','exam-march-2f177042',86,'현재 중간고사 시험 범위 진도는 완료되었습니다. 앞으로 다양한 유형의 문제풀이와 심화 문제풀이 그리고 서술형문제풀이를 중심으로 수업을 진행할 예정입니다. ','2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-b9ca7c18','student-odmyl712f','exam-march-2f177042',77,'','2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-dae9e62b','student-qv5fihk50','exam-march-2f177042',73,'현재 중간고사 시험 범위의 진도는 완료된 상태입니다. 현재 기본 개념 문제풀이는 실수가 적지만 심화 유형이나 서술형 유형의 문제를 풀 때, 1단원 시분야에서 실수가 많이 있습니다. 문학분야 문제를 많이 어려워 해서 앞으로의 수업동안 도현이가 어려워하는 부분의 심화문제와 서술형 문제풀이를 통해서 꼼꼼하게 중간고사를 준비하려고 합니다. ','2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-c5f05d67','student-s54ihowlx','exam-march-2f177042',45,'현재 수능특강과 국어 어휘공부를 중심으로 수업을 진행하고 있습니다. 아직 국어 문제를 풀 때, 모르는 어휘가 많지만, 매 수업마다 어휘를 꾸준하게 공부해서 실력을 쌓을 수 있도록 수업을 진행할 예정입니다 ','2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-05adbb1f','student-i7k4uy8ml','exam-march-2f177042',73,'현재 시험범위 단원의 개념 기본 문제는 잘 풀지만 심화 문제나 사고력 문제 풀이에는 실수가 있습니다. 중간고사는 국어를 중심으로 수업을 진행할 예정입니다. ','2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-fb1bd0ea','student-egoh2pw9x','exam-march-2f177042',86,'현재 중간고사 시험 범위의 진도는 완료된 상태입니다. 현재 기본 개념 문제풀이는 실수가 적지만 심화 유형이나 서술형 유형의 문제를 풀 때, 1단원 시분야에서 실수가 많이 있습니다. 문학분야 문제를 많이 어려워 해서 앞으로의 수업동안 도현이가 어려워하는 부분의 심화문제와 서술형 문제풀이를 통해서 꼼꼼하게 중간고사를 준비하려고 합니다. ','2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-ed9192d2','student-k8kamd4y8','exam-march-2f177042',54,'현재 1단원 진도가 완료되고 시험 범위인 2단원은 곧 마무리 됩니다. 기본 개념 문제는 실수가 적은 편이나 아직까지 어휘력이 부족해서 문제를 분석할 때 실수가 있어서 아는 문제도 틀리는 경우가 많이 있습니다. 앞으로 어휘공부와 다양한 유형의 문제풀이를 통해서 중간고사 대비를 꼼꼼하게 진행할 예정입니다. ','2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-7a60e33c','student-p3kgxnsyw','exam-march-2f177042',60,'현재 정화중은 시험범위가 계속 바뀌고 있습니다. 그래서 중간고사 대비를 더 꼼꼼하게 진행하고 있습니다. 예지는 기본개념문제풀이는 실수가 적은 편이나 복수정답 유형의 문제나 심화문제풀이시 실수가 있어서 앞으로의 수업을 통해서 이러한 부족한 부분을 채울 수 있도록 수업을 진행할 예정입니다. ','2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-574c8d61','student-j59157jnh','exam-march-2f177042',100,'이번 정기고사 시험범위는 3단원입니다. 3단원의 개념을 확실하게 알고 있고 수업시간에 어려워 했던 문제도 잘 풀었습니다. 앞으로 진도와 복습 함께 병행하면서 중학교 대비를 조금씩 진행하도록 하겠습니다. ','2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-fd4bd5a4','student-enwewi2vj','exam-march-2f177042',67,'현재 시험 범위 진도는 완료된 상태이고 앞으로 수업시간에 다양한 유형의 문제풀이와 심화 문제, 서술형 문제풀이를 하면서 시험 준비를 꼼꼼하게 진행할 예정입니다. ','2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-89dbe218','student-ue92sdab0','exam-march-2f177042',50,'현재 학교진도에 맞추어서 수업을 진행하고 있습니다. 하진이 학교는 중간고사 5월달에 진행되기에 개념과 문제를 반복하면서 중간고사를 준비할 예정입니다. 객관식 위주의 시험이기에 반복 훈련을 통해서 꼼꼼하게 시험을 준비할 예정입니다. ','2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-93f76b80','student-nb8y8m656','exam-march-8fdb908d',67,replace('루다는 영어 공부에 대한 열의가 대단하며, 수업 분위기를 밝고 긍정적으로 만들어주는 큰 장점을 가진 학생입니다. 매번 숙제를 완벽히 해결해 오는 것은 물론, 모르는 부분이 생기면 주저 없이 질문하여 자기 것으로 만드는 능동적인 태도가 돋보입니다.\n특히 자기주도적 학습 능력이 잘 갖춰져 있어 앞으로의 성장이 더욱 기대됩니다. 다가오는 시험 대비 기간에도 지금의 활기찬 에너지를 바탕으로 최선의 결과를 낼 수 있도록 곁에서 철저히 지도하겠습니다.','\n',char(10)),'2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-fcb502ec','student-2vqo23cgs','exam-march-8fdb908d',80,replace('민준이는 항상 밝고 건강한 에너지를 뿜어내어 주변까지 기분 좋게 만드는 학생입니다. 수업 시간에는 선생님의 지도에 귀를 잘 기울이며, 맡겨진 과제를 거부감 없이 차근차근 해나가는 모습이 무척 대견합니다.\n민준이가 영어 공부에 흥미를 잃지 않고 즐겁게 한 걸음씩 나아갈 수 있도록 칭찬과 격려로 세심하게 지도하겠습니다.','\n',char(10)),'2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-1674989b','student-0mc8orloi','exam-march-8fdb908d',60,replace('새로운 개념을 설명해 주면 금방 파악하고 따라오는 영리함이 돋보입니다.\n본인이 마음먹고 집중할 때는 충분히 좋은 성과를 낼 수 있는 능력을 갖추고 있습니다. 다가오는 시험 기간에는 성준이가 가진 이러한 재능을 십분 발휘하여 실질적인 점수 향상으로 이어질 수 있도록 곁에서 강하게 독려하겠습니다.','\n',char(10)),'2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-92e98f5a','student-a7wi0zma6','exam-march-8fdb908d',13,replace('지효는 항상 밝고 활기찬 에너지로 수업 분위기를 좋게 만들어주는 매력적인 학생입니다. 비록 당장의 시험 성적은 조금 아쉬움이 남지만, 주어진 과업을 완수하기 위해 끝까지 노력하는 모습이 무척 대견합니다.\n지효처럼 바른 학습 태도와 의지를 갖춘 학생은 시간이 흐를수록 더 큰 성장을 보여줍니다. 다가오는 시험 대비 기간에는 지효가 노력한 만큼 성취감을 맛볼 수 있도록 더욱 세심하게 이끌고 지도하겠습니다.','\n',char(10)),'2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-2a21daba','student-rks9au7mm','exam-march-8fdb908d',47,replace('하진이는 항상 밝고 긍정적인 태도로 수업에 임하며, 주어진 과업을 성실하게 완수해내는 믿음직한 학생입니다. 특히 수행평가나 영어듣기 평가처럼 대비가 필요한 영역에서 누구보다 열정적으로 준비하는 모습이 무척 대견합니다.\n평소의 유연한 모습 속에, 꼭 해내야 하는 중요한 순간에는 무서운 집중력을 발휘하는 강점이 있습니다. 이번 시험 대비 기간에도 하진이가 가진 이 집중력을 십분 발휘하여 만족스러운 결과를 얻을 수 있도록 세심하게 지도하겠습니다.','\n',char(10)),'2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-be552348','student-fbcy3xfzp','exam-march-8fdb908d',53,replace('지후는 다른 학생들과는 다르게 수업 시간 중 휴대폰을 만지는 등의 흐트러지는 모습 없이 묵묵히 제 자리를 지키는 성실함을 가지고 있습니다. 때때로 조금 느슨해질 때도 있지만, 적절한 격려와 응원을 보내주면 금세 의욕을 보이며 곧잘 따라와 주는 학생입니다.\n특히 이번 학교 수행평가 기간에는 본인이 맡은 부분을 성실하게 준비하는 모습이 인상적이었습니다. 지후가 가진 성실한 기본기에 자신감만 더해진다면 앞으로 더 큰 성장을 이룰 수 있을 것입니다.','\n',char(10)),'2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-a0723881','student-ue92sdab0','exam-march-8fdb908d',33,replace('최근 하진이는 수업 태도에서 긍정적인 변화를 보여주고 있습니다. 초반에 비해 수업 중 집중력이 좋아졌으며, 끝까지 깨어 있으려 노력하며 수업에 참여하고 있습니다.\n이러한 집중력의 개선은 곧 성적 향상으로 이어질 소중한 신호입니다. 지금의 태도를 꾸준히 유지하여 실질적인 점수 상승을 경험할 수 있도록 곁에서 잘 이끌겠습니다.','\n',char(10)),'2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-37ecb724','student-y1ov7jvh5','exam-march-8fdb908d',80,replace('예원이는 수업 태도가 바르고, 주어진 학습 과제를 성실하게 이행하는 학생입니다. 현재는 기초 지식을 쌓아가는 단계라 보완할 점이 있지만, 모르는 부분이 생기면 적극적으로 질문하여 해결하려는 자세가 아주 훌륭합니다.\n특히 이번 영어듣기 평가를 위해 열심히 준비한 결과, 100점이라는 최고의 성적을 거두었습니다. 이러한 성공 경험을 바탕으로 자신감을 가지고 꾸준히 정진한다면, 중간고사에서도 분명 좋은 결실을 볼 수 있을 것이라 믿습니다.','\n',char(10)),'2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-03926915','student-8p9l1h85l','exam-march-8fdb908d',20,replace('슬아는 성품이 착하고 고우며, 특히 집중했을 때 영어 단어를 암기하는 감각이 좋습니다.\n이제 곧 다가올 시험을 대비하여 슬아 스스로도 마음을 다잡고 열심히 준비해보겠다는 의지를 보이고 있습니다. 슬아가 자신의 암기 재능을 발휘해 좋은 성과를 거두고 성취감을 맛볼 수 있도록 곁에서 적극적으로 격려하며 지도하겠습니다.','\n',char(10)),'2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-d367b734','student-xi4i833h1','exam-march-8fdb908d',20,replace('채원이는 학습 태도가 매우 성실하고 공부하려는 의지가 강한 학생입니다. 현재는 기초 지식을 쌓아가는 단계라 절대적인 학습량이 다소 부족하여 성적 면에서 아쉬움이 남습니다.\n하지만 지금처럼 바른 태도를 유지하며 꾸준히 학습 총량을 늘려간다면, 부족한 부분이 채워지면서 점진적으로 실력이 향상될 것입니다.','\n',char(10)),'2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-136377c9','student-j5ohbrke6','exam-march-8fdb908d',73,replace('도윤이는 항상 성실한 태도로 수업에 임하며, 수업 시간 내내 흐트러짐 없는 집중력을 보여주는 모범적인 학생입니다. 특히 독해 능력이 매우 뛰어나 문장 구조를 파악하는 힘이 좋습니다. 무엇보다 스스로 모르는 단어를 갈무리하여 ‘자기만의 단어장’을 만드는 모습에서 영어 학습에 대한 깊은 열정과 주도적인 학습 습관을 확인할 수 있었습니다.\n\n지금처럼 꾸준히 정진한다면 수능에서도 충분히 상위권 성적을 거둘 것으로 기대됩니다. 다만, 탄탄한 실력을 갖춘 만큼 스스로 확신을 가질 때 간혹 세부적인 부분을 놓쳐 발생하는 실수가 종종 보입니다. 도윤이가 자신의 실력에 자만하지 않고 끝까지 꼼꼼함을 유지할 수 있도록 원에서 세밀하게 지도하겠습니다.','\n',char(10)),'2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-a4dd91b6','student-odmyl712f','exam-march-8fdb908d',60,'도훈이는 겉으로 드러나는 모습보다 훨씬 내실 있고 책임감이 강한 학생입니다. 언뜻 무심해 보일 때도 있지만, 정작 학습 지시를 내리면 단 한 번도 빠뜨리지 않고 묵묵히 성실하게 이행해냅니다.','2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-d9294605','student-t1xikskhy','exam-march-8fdb908d',20,replace('동민이는 수업 시간 내내 흐트러짐 없는 집중력을 유지하며, 맡은 바를 끝까지 완수해내는 근성이 뛰어난 학생입니다.\n어떠한 과제에도 뒤로 물러나지 않고 묵묵히 정진하는 모습에서 영어 학습에 대한 진지함을 느낄 수 있습니다. 이러한 훌륭한 수업 태도는 성적 향상의 가장 단단한 밑거름이 될 것이라 믿습니다.','\n',char(10)),'2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-b2c84996','student-ryf96197t','exam-march-8fdb908d',40,replace('지안이는 특유의 밝고 명랑한 성격으로 수업 분위기를 기분 좋게 만들어 주는 학생입니다. 가끔 본인의 영어 실력에 대해 다소 조심스럽거나 자신감이 부족한 모습을 보일 때도 있지만, 실제 학습 태도는 누구보다 훌륭합니다.\n\n주어진 과제나 수업 내용을 요령 피우지 않고 성실하게 이행하는 모습이 인상적입니다. 이러한 노력이 쌓이면 곧 실력 향상이라는 결과로 이어져 큰 자신감을 얻게 될 것입니다. 지안이가 본인의 가능성을 믿고 즐겁게 공부할 수 있도록 칭찬과 격려로 세심하게 지도하겠습니다.','\n',char(10)),'2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-294e0686','student-j59157jnh','exam-march-8fdb908d',53,replace('태현이는 수업 태도가 매우 성실하며, 평소 내어주는 숙제 또한 빠짐없이 잘 해오는 학생입니다. 이번에는 태현이의 실력을 확인해보고자 초등 과정을 넘어선 중등 수준의 시험을 치르게 했습니다.\n난이도가 높은 문제였음에도 불구하고 곧잘 풀어내는 모습에서 학습 잠재력을 확인할 수 있었습니다. 표면적인 점수보다 상급 수준의 문항을 소화해냈다는 점에 더 큰 의미가 있습니다. 앞으로도 태현이가 더욱 자신감을 가지고 실력을 쌓아갈 수 있도록 성실히 지도하겠습니다.','\n',char(10)),'2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-c7c06aeb','student-yxu4r4ae9','exam-march-8fdb908d',73,replace('예지는 수업 태도가 매우 성실하며, 주어진 숙제와 과업을 잘 이행해 오는 신뢰감 있는 학생입니다. 특히 영어에 대한 이해도가 높아 새로운 개념을 빠르게 습득하며, 스스로 학습을 이끌어가는 능력이 무척 뛰어납니다.\n자기주도적인 학습 습관이 잘 잡혀 있어 지도하는 입장에서 큰 걱정이 되지 않을 만큼 믿음직스럽습니다. 지금처럼 흔들림 없이 정진한다면 앞으로도 안정적으로 좋은 성적을 낼 수 있을거라 생각합니다.','\n',char(10)),'2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-d41a583d','student-4s1rdnhpb','exam-march-8fdb908d',40,replace('순우는 평소 수업 태도가 매우 성실하며, 단 한 번의 딴짓도 없이 오직 학습에만 전념하는 모습이 무척 대견한 학생입니다.\n비록 당장의 시험 성적은 조금 아쉬움이 남지만, 순우가 보여주는 흔들림 없는 태도를 유지한다면 반드시 성적이 오를 것이라 확신합니다. 다가오는 시험을 철저히 준비하여 순우의 성실함이 빛을 발할 수 있도록 최선을 다해 지도하겠습니다.','\n',char(10)),'2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-95ff1979','student-egoh2pw9x','exam-march-8fdb908d',87,replace('승민이는 자기주도적 학습 습관이 잘 잡혀 있는 뛰어난 모범생입니다. 압박을 가하지 않아도 스스로 공부할 거리를 찾아내며 선생님에게 더 공부시켜달라고 요구하는 성실한 학생입니다. 높은 이해력을 바탕으로 고등학교 수준의 문항들까지 잘 풀어내고 있습니다.\n수업 태도 또한 나무랄 데 없이 훌륭하여 매 시간 깊이 있는 학습이 이루어지고 있습니다. 이번 중간고사를 철저히 준비하여 승민이의 탄탄한 실력이 실질적인 성적 향상으로 증명될 수 있도록 만전을 기하겠습니다.','\n',char(10)),'2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-e263c4d1','student-6cxbm886s','exam-march-8fdb908d',27,replace('윤재는 시험 성적과 별개로 수업 시간에는 꾸준한 성실함을 보여주고 있습니다. 다만 아직은 절대적인 학습량이 다소 부족하여 실질적인 점수 상승으로 이어지기까지 시간이 필요한 단계입니다.\n최근 학교 수행평가를 매우 착실히 준비하는 모습을 보여준 만큼, 이러한 성실함을 꾸준히 유지하여 전체적인 학습량을 늘려간다면 앞으로 더 나은 결과를 얻을 수 있을 것입니다.','\n',char(10)),'2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-badad828','student-k8kamd4y8','exam-march-8fdb908d',27,replace('도은이는 수업 시간에 지시하는 학습 내용을 끝까지 완수해내려는 의지가 돋보이는 학생입니다.\n이러한 끈기는 실력 향상을 위한 가장 중요한 밑거름입니다. 다가오는 시험 대비 기간에는 도은이의 눈높이에 맞춘 반복 학습과 세밀한 지도를 통해, 아이가 공부에 대한 자신감을 얻고 성취감을 느낄 수 있도록 최선을 다하겠습니다.','\n',char(10)),'2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-f76caa7f','student-q5ecu8748','exam-march-8fdb908d',60,replace('지후는 항상 묵묵하게 자신이 맡은 학습량을 채워 나가는 믿음직한 학생입니다. 주어진 숙제를 빠짐없이 해결해 오는 성실함은 물론, 수업 시간에도 흐트러짐 없는 좋은 태도를 유지하고 있습니다.\n이러한 꾸준함이 지후의 실력을 지탱하는 가장 큰 힘이 될 것입니다. 이번 시험 대비 기간에도 지후가 최선의 결과를 낼 수 있도록 꼼꼼히 지도하겠습니다.','\n',char(10)),'2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-8446797f','student-tx3blu2og','exam-march-8fdb908d',60,replace('혜연이는 영어에 대한 이해도가 높으며, 수업 시간에 집중하는 태도가 아주 우수한 학생입니다. 특히 학습량이 적지 않음에도 불구하고 항상 숙제를 완벽하게 해결해 오는 꾸준함이 혜연이의 가장 큰 자산입니다.\n기본 실력과 성실함을 고루 갖추고 있어 앞으로의 성장이 더욱 기대되는 학생입니다. 다가오는 시험 대비 기간에도 지금의 페이스를 잘 유지하며 실전에서 최고의 실력을 발휘할 수 있도록 꼼꼼하게 지도하겠습니다.','\n',char(10)),'2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-5000ef25','student-3mzmc3kin','exam-march-8fdb908d',33,replace('혜정이는 항상 밝고 긍정적인 모습으로 수업 분위기를 활기차게 만들어주는 학생입니다. 수업 시간에는 항상 바른 태도로 임하며, 학습 지시를 내리면 집중력을 발휘해 완수해내는 수행 능력이 뛰어납니다.\n이러한 몰입도는 실전에서 실수를 줄이고 실력을 발휘하는 데 큰 밑거름이 될 것입니다. 다가오는 시험 대비 기간에도 혜정이가 지금의 에너지를 잃지 않고 즐겁게 몰입하여 최상의 결과를 얻을 수 있도록 곁에서 힘껏 응원하며 지도하겠습니다.','\n',char(10)),'2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-3711c435','student-y1ov7jvh5','exam-march-3fb325cc',73,'지난 정기고사 대비 정답률이 다소 낮아졌습니다. 남은 진도 마무리하고 다시 복습하면서 어떤 개념들을 집중해서 공부해야 되는지 체크할 예정입니다.','2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-27f07070','student-rks9au7mm','exam-march-3fb325cc',27,'고등으로 들어오면서 과학의 개념 자체의 난이도가 많이 상승했습니다. 따라서 개념을 확실하게 숙지하지 않으면 모든 문제들이 선택지 하나에 의해 정답이 갈릴 수 있습니다. 좀 더 개념을 확실하게 숙지할 수 있도록 수업 진행할 예정입니다.','2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-905eaaa9','student-fbcy3xfzp','exam-march-3fb325cc',60,'지난 정기고사 대비 정답률이 다소 상승했습니다. 다만 난이도가 낮은 개념 문제들에 오답이 많이 나왔는데 좀 더 확실하게 개념을 숙지할 수 있도록 수업 진행할 예정입니다.','2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-b7492cff','student-i7k4uy8ml','exam-march-3fb325cc',80,'시험대비 문제풀이와 오답정리에 집중하고 있습니다. 오답 정리를 통해 어떤 개념을 좀 더 확실하게 숙지해야 되는지 체크하면서 수업 진행할 예정입니다.','2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
