INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-1be188a0','student-nb8y8m656','exam-march-3fb325cc',53,'화학양론과 양적관계에서 나오는 고난이도 추론문제 위주로 출제하였습니다. 추론문제의 정답률이 다소 낮게 형성되었기 때문에 추론문제 풀이 연습에 좀 더 시간을 많이 투자할 예정입니다.','2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
