INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-38e72f0d','student-7gioy6c0x','exam-march-3fb325cc',53,'생명체의 중심이론과 DNA복제에 대해서 진도 나가고 있습니다. 개념이 다소 어렵지만 방학 중 한번 다루었던 내용들이기 때문에 잘 따라오고 있습니다.','2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-97f54ecf','student-m154cgywx','exam-march-3fb325cc',40,'자료해석 문제와 추론문제에서 오답이 주로 나왔습니다. 좀 더 다양한 문제들을 풀고 여러 유형들에 대처할 수 있도록 수업 진행할 예정입니다.','2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
