INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-c0a15f52','student-j59157jnh','exam-march-3fb325cc',93,'물체의 운동 단원 마무리 하고 식물과 현미경 진도 나갈 예정입니다. 이번 단원도 태현이가 잘 이해하고 넘어갈 수 있도록 수업 진행 하겠습니다.','2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-35189a70','student-a7wi0zma6','exam-march-3fb325cc',60,'시험대비 문제풀이와 오답정리에 집중하고 있습니다. 오답 정리를 통해 어떤 개념을 좀 더 확실하게 숙지해야 되는지 체크하면서 수업 진행할 예정입니다.','2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-561c7efc','student-0spi35f7j','exam-march-7bd10c98',40,'화학은 화학양론과 양적관계에서 나오는 고난이도 추론문제 위주로 출제하였습니다. 추론문제의 정답률이 다소 낮게 형성되었기 때문에 추론문제 풀이 연습에 좀 더 시간을 많이 투자할 예정입니다.','2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-ed02a1e1','student-0spi35f7j','exam-march-6794c68f',80,'생명과학은 자료해석 문제와 추론문제에서 오답이 주로 나왔습니다. 좀 더 다양한 문제들을 풀고 여러 유형에 대처할 수 있도록 수업 진행할 예정입니다.','2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-8fd4dbac','student-p3kgxnsyw','exam-march-ca534978',53,' 예지는 기본개념문제풀이는 실수가 적은 편이나 복수정답 유형의 문제나 심화문제풀이 특히, 지도문제에 실수가 있어서 앞으로의 수업을 통해서 이러한 부족한 부분을 채울 수 있도록 수업을 진행할 예정입니다. ','2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-23cd1869','student-i7k4uy8ml','exam-march-ca534978',80,'기본개념문제풀이는 실수가 적은 편이나 복수정답 유형의 문제나 심화 문제에는 실수가 있습니다. 중간고사 때는 한국사 시험이 미실시되지만 기말고사 준비를 수업시간마다 조금씩 진행해서 기말고사 준비를 잘 할 수 있도록 수업을 진행할 예정입니다. ','2026-04-09 09:59:10','user-57ppx9v61','2026-04-09 09:59:10','2026-03');
