INSERT INTO "grades" ("id","student_id","exam_id","score","comments","graded_at","graded_by","created_at","year_month") VALUES('grade-7f359c0f','student-5645a3fs4','exam-17c94e85',90,replace('이번 정기고사에서는 90점을 받았습니다. 객관식및 서술형으로 문제를 구성을 헀는데 서술형 1문제 객관식 1문제를 틀렸습니다. \n가끔 집중력을 읽고, 이야기를 할려고 하지만 그것말고는 괜찮습니다. 센스와 머리가 좋은 학생입니다. 정의 문제와 풀이가 어려운 한문제씩 틀렸고, 정의도 슬쩍 문제를 몇 번 풀리면 이해를 할 것 같고, 고난이도 문제를 많이 풀어보게 하면서 실수를 유도를 하면서 혼자서 생각을 해보도록 지도를 하겠습니다','\n',char(10)),'2026-04-21T08:36:05.578Z','user-57ppx9v61','2026-04-09T14:57:30.740Z','2026-04');
