INSERT INTO "vocab_grammar_qa" ("id","academy_id","student_id","question","answer","status","answered_by","include_in_print","created_at","answered_at") VALUES('vqa-a47ddb33','acad-1','gstu-25ae7a2c','가정법 과거와 가정법 과거완료의 차이를 설명해주세요',replace('가정법 과거는 현재 사실의 반대를 가정할 때 사용합니다. 예) If I were rich, I would travel the world. (실제로는 부자가 아님)\n\n가정법 과거완료는 과거 사실의 반대를 가정할 때 사용합니다. 예) If I had studied harder, I would have passed the exam. (실제로는 열심히 공부하지 않았음)\n\n핵심 차이: 시제 기준점이 현재냐 과거냐의 차이입니다.','\n',char(10)),'answered','ai',0,'2026-03-20T10:00:00.000Z','2026-03-20T10:00:00.000Z');
INSERT INTO "vocab_grammar_qa" ("id","academy_id","student_id","question","answer","status","answered_by","include_in_print","created_at","answered_at") VALUES('vqa-88af15bb','acad-1','gstu-ffb51170','관계대명사 that과 which의 차이가 뭔가요?',replace('주요 차이점:\n1. 선행사: that은 사람/사물 모두, which는 사물만\n2. 계속적 용법: which만 가능 (콤마 + which)\n3. 전치사 앞: which만 가능 (in which, with which)\n\n예) The book which/that I bought is interesting. (둘 다 가능)\nThe book, which I bought yesterday, is interesting. (which만 가능)','\n',char(10)),'answered','ai',0,'2026-03-21T11:00:00.000Z','2026-03-21T11:00:00.000Z');
INSERT INTO "vocab_grammar_qa" ("id","academy_id","student_id","question","answer","status","answered_by","include_in_print","created_at","answered_at") VALUES('vqa-2fda5665','acad-1','gstu-25ae7a2c','to부정사와 동명사를 목적어로 취하는 동사 구별법이 있나요?',NULL,'pending',NULL,0,'2026-04-01T09:00:00.000Z',NULL);
